const fs=require('fs');
const data=fs.readFileSync(0,'utf-8').trim().split(/\s+/).map(Number);
let idx=0;
const T=data[idx++];
let out=[];
for(let t=0;t<T;++t){
  const N=data[idx++];
  const Q=data[idx++];
  const pref=new Array(N+1);
  pref[0]=0;
  for(let i=1;i<=N;++i){
    const x=data[idx++];
    pref[i]=pref[i-1]^x;
  }
  for(let i=0;i<Q;++i){
    const k=data[idx++];
    const r=k%(N+1);
    out.push(String(pref[r]));
  }
}
